// Fallback to 'herstal' if param is missing or invalid
const getCommuneFromUrl = (): CommuneConfig => {
  if (typeof window === 'undefined') return COMMUNES_DB['herstal'];

  const params = new URLSearchParams(window.location.search);
  const slug = (params.get('commune') || 'herstal').toLowerCase();

  return COMMUNES_DB[slug] || COMMUNES_DB['herstal'];
};

